const raw = $input.all();
const NL = String.fromCharCode(10);
let scripts = [];
for (const item of raw) {
  const d = item.json;
  if (d.body && Array.isArray(d.body)) {
    for (const s of d.body) { scripts.push({ json: s }); }
  } else if (d.pine_code) { scripts.push(item); }
}
const valid = scripts.filter(item => {
  const code = item.json.pine_code || '';
  return code.length > 50 && !code.startsWith('REQUIRES_BROWSER') && !code.startsWith('PROTECTED') && (code.includes('//@version') || code.includes('indicator(') || code.includes('strategy('));
});
if (valid.length === 0) {
  return [{ json: { _no_scripts: true, message: 'No valid Pine scripts. ' + scripts.length + ' received.', total_scraped: scripts.length, timestamp: new Date().toISOString() } }];
}
const SYSTEM_PROMPT = ['You are a quant strategist. Analyze this Pine Script.', 'Respond in JSON only: {"strategy_summary":"...","risk_profile":"...","overall_score":1-10,', '"estimates":{"net_return_pct":0,"win_rate_pct":0,"profit_factor":0,"max_drawdown_pct":0,"sharpe_ratio":0,"num_trades":0},', '"analysis":"2-3 sentences"}. Return ONLY JSON.'].join(NL);
return valid.map(item => {
  const d = item.json;
  const title = d.title || 'Unknown';
  const author = d.author || 'Unknown';
  const desc = (d.description || '').substring(0, 500);
  const code = (d.pine_code || '').substring(0, 6000);
  const userPrompt = ['Title: ' + title, 'Author: ' + author, 'Desc: ' + desc, 'Pine Code:', code].join(NL);
  return { json: { title, author, description: d.description || '', pine_code: d.pine_code || '', script_url: d.script_url || '', category: d.category || '', screenshot_url: d.screenshot_url || '', api_body: JSON.stringify({ model: 'sonar', messages: [{ role: 'system', content: SYSTEM_PROMPT }, { role: 'user', content: userPrompt }], temperature: 0.1 }) } };
});

// Parse merged LLM responses + metadata, extract scores, rank
const items = $input.all();
const results = [];

for (const item of items) {
  const d = item.json;

  // Original metadata (from merge input 2)
  const title = d.title || 'Unknown';
  const author = d.author || 'Unknown';
  const scriptUrl = d.script_url || '';
  const category = d.category || '';

  // Parse LLM response (from merge input 1)
  let llmText = '';
  let parsed = null;

  try {
    if (d.choices && d.choices[0] && d.choices[0].message) {
      llmText = d.choices[0].message.content || '';
    }
    let cleanText = llmText.replace(/```json\s*/gi, '').replace(/```\s*/gi, '').trim();
    const jsonMatch = cleanText.match(/\{[\s\S]*\}/);
    if (jsonMatch) {
      parsed = JSON.parse(jsonMatch[0]);
    }
  } catch (e) {
    // Parse failed - use defaults
  }

  const est = parsed?.estimates || {};
  const score = Number(parsed?.overall_score) || 0;
  const netPct = Number(est.net_return_pct) || 0;
  const winRate = Number(est.win_rate_pct) || 0;
  const pf = Number(est.profit_factor) || 0;
  const maxDd = Number(est.max_drawdown_pct) || 0;
  const sharpe = Number(est.sharpe_ratio) || 0;
  const trades = Number(est.num_trades) || 0;

  results.push({
    json: {
      title, author, script_url: scriptUrl, category, score,
      est_net_pct: netPct, est_win_rate: winRate, est_profit_factor: pf,
      est_max_dd: maxDd, est_sharpe: sharpe, est_trades: trades,
      strategy_summary: parsed?.strategy_summary || 'Analysis failed',
      risk_profile: parsed?.risk_profile || 'Unknown',
      llm_analysis: parsed?.analysis || llmText.substring(0, 1000),
      analyzed_at: new Date().toISOString()
    }
  });
}

// Sort by composite: score * (winRate/100) * max(pf,0.1) * max(sharpe,0.1)
results.sort((a, b) => {
  const compA = a.json.score * (a.json.est_win_rate / 100) * Math.max(a.json.est_profit_factor, 0.1) * Math.max(a.json.est_sharpe, 0.1);
  const compB = b.json.score * (b.json.est_win_rate / 100) * Math.max(b.json.est_profit_factor, 0.1) * Math.max(b.json.est_sharpe, 0.1);
  return compB - compA;
});

results.forEach((r, i) => { r.json.rank = i + 1; });
return results;

// Top 3 scripts with scores, one-line summary, and TradingView link
const items = $input.all();
const top3 = items.filter(i => i.json.score > 0).slice(0, 3);
const NL = String.fromCharCode(10);

if (top3.length === 0) {
  return [{ json: { message: 'Hybrid Discovery: No noteworthy scripts found this run.' } }];
}

const esc = (s) => (s || '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');

const lines = [];
lines.push('<b>' + String.fromCharCode(9889) + ' Quantum Discovery - Top ' + top3.length + '</b>');
lines.push('');

for (const item of top3) {
  const d = item.json;
  const stars = d.score >= 8 ? String.fromCharCode(11088) : d.score >= 6 ? String.fromCharCode(10004) : String.fromCharCode(9679);
  lines.push(stars + ' <b>' + esc(d.title) + '</b> [' + d.score + '/10]');
  lines.push('   ' + esc((d.strategy_summary || '').substring(0, 120)));
  if (d.script_url) {
    lines.push('   ' + String.fromCharCode(128279) + ' <a href="' + d.script_url + '">Add to TradingView</a>');
  }
  lines.push('');
}

lines.push('<i>' + items.length + ' scripts analyzed ' + String.fromCharCode(8226) + ' ' + new Date().toISOString().substring(0, 10) + '</i>');

return [{ json: { message: lines.join(NL) } }];

// Discovery Queue - top 3 scripts with full LLM analysis
const items = $input.all();
const top3 = items.slice(0, 3);

if (top3.length === 0) {
  return [{ json: { queue_status: 'EMPTY', message: 'No scripts queued.', timestamp: new Date().toISOString() } }];
}

console.log('=== DISCOVERY QUEUE @ ' + new Date().toISOString() + ' ===');

return top3.map((item, idx) => {
  const d = item.json;
  console.log('#' + (idx + 1) + ': ' + d.title + ' (Score: ' + d.score + '/10, Net: ' + d.est_net_pct + '%)');
  return {
    json: {
      queue_rank: idx + 1,
      title: d.title, author: d.author, script_url: d.script_url,
      score: d.score, est_net_pct: d.est_net_pct, est_win_rate: d.est_win_rate,
      est_profit_factor: d.est_profit_factor, est_sharpe: d.est_sharpe,
      strategy_summary: d.strategy_summary, risk_profile: d.risk_profile,
      llm_analysis: d.llm_analysis, queued_at: new Date().toISOString()
    }
  };
});

const item = $input.first().json;
console.log('Hybrid Discovery: ' + item.message);
return [{ json: { message: 'Hybrid Discovery: ' + item.message, timestamp: new Date().toISOString() } }];
